const N8N_BASE = 'https://n8n.csr-llc.tech';
const API_KEY = $env?.N8N_API_KEY || '';

// Plain-English cause classifier
function classifyCause(msg, nodeName) {
  if (!msg) return 'Unknown error';
  const m = msg.toLowerCase();
  if (m.includes('unauthorized') || m.includes('403') || m.includes('auth')) {
    return 'Authentication failed — wrong or expired API key sent to this workflow';
  }
  if (m.includes('fetch is not defined') || m.includes('fetch is not')) {
    return 'Workflow uses fetch() which is not available in n8n — needs httpRequest helper';
  }
  if (m.includes('404') || m.includes('not found')) {
    return 'Endpoint not found — workflow path may have changed or been removed';
  }
  if (m.includes('500') || m.includes('internal server')) {
    return 'Downstream workflow returned a 500 internal error';
  }
  if (m.includes('timeout') || m.includes('timed out') || m.includes('econnreset')) {
    return 'Request timed out — downstream workflow too slow or unresponsive';
  }
  if (m.includes('cannot read') || m.includes('undefined') || m.includes('null')) {
    return 'Workflow crashed on bad data — a required field was null or undefined';
  }
  if (m.includes('enotfound') || m.includes('econnrefused')) {
    return 'Network error — could not reach the target host';
  }
  return msg.length > 120 ? msg.slice(0, 120) + '...' : msg;
}

function suggestAction(msg, nodeName) {
  if (!msg) return 'Inspect the workflow in n8n and check the error node';
  const m = msg.toLowerCase();
  if (m.includes('unauthorized') || m.includes('auth') || m.includes('403')) {
    return 'Check the x-gda-key or auth_key value being sent — it may have rotated';
  }
  if (m.includes('fetch is not defined')) {
    return 'Replace fetch() with this.helpers.httpRequest() in the Code node';
  }
  if (m.includes('404')) {
    return 'Verify the webhook path exists and the workflow is active in n8n';
  }
  if (m.includes('500')) {
    return 'Open the failing downstream workflow in n8n and check its execution log';
  }
  if (m.includes('timeout') || m.includes('econnreset')) {
    return 'Increase the timeout or check if the downstream service is running';
  }
  if (m.includes('cannot read') || m.includes('undefined')) {
    return 'Add null checks in the Code node before accessing nested fields';
  }
  return 'Open n8n execution log for this workflow and inspect the failing node';
}

// Fetch recent error executions via n8n API
let executions = [];
try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: `${N8N_BASE}/api/v1/executions?status=error&limit=25`,
    headers: {
      'X-N8N-API-KEY': API_KEY,
      'Accept': 'application/json'
    },
    json: true
  });
  executions = resp.data || [];
} catch(e) {
  return [{ json: {
    success: false,
    workflow: 'GDA.qa.latest-failures',
    action: 'latest-failures',
    dryRun: true,
    data: null,
    error: 'Could not reach n8n executions API: ' + (e.message || 'unknown error'),
    meta: { count: 0, generatedAt: new Date().toISOString() }
  }}];
}

// Fetch workflow name map (top 100 workflows)
let workflowNames = {};
try {
  const wfResp = await this.helpers.httpRequest({
    method: 'GET',
    url: `${N8N_BASE}/api/v1/workflows?limit=100`,
    headers: {
      'X-N8N-API-KEY': API_KEY,
      'Accept': 'application/json'
    },
    json: true
  });
  for (const wf of (wfResp.data || [])) {
    workflowNames[wf.id] = wf.name;
  }
} catch(e) {
  // Non-fatal — proceed without names
}

// Normalize each failure
const failures = [];
const seen = new Set();

for (const ex of executions) {
  const wfId = ex.workflowId || '';
  const key = wfId + '|' + (ex.errorInfo?.primaryError?.message || '');
  if (seen.has(key)) continue; // dedupe same workflow+error
  seen.add(key);

  const primary = ex.errorInfo?.primaryError || {};
  const msg = primary.message || 'No error message available';
  const nodeName = primary.nodeName || 'unknown node';
  const wfName = workflowNames[wfId] || wfId;

  // Skip the ssh-read-file utility workflow from cluttering results
  if (wfName.includes('ssh-read') || wfName.includes('util.ssh')) continue;

  failures.push({
    workflowName: wfName,
    workflowId: wfId,
    nodeName,
    status: 'fail',
    failedAt: ex.stoppedAt || ex.startedAt || null,
    cause: classifyCause(msg, nodeName),
    nextAction: suggestAction(msg, nodeName)
  });

  if (failures.length >= 15) break;
}

return [{ json: {
  success: true,
  workflow: 'GDA.qa.latest-failures',
  action: 'latest-failures',
  dryRun: true,
  data: { failures },
  error: null,
  meta: { count: failures.length, generatedAt: new Date().toISOString() }
}}];
